using UnityEngine;

// Condições do Sistema de Pistas/Rumores (Diário) — aparecem automaticamente
// no "+ Adicionar Condição" de qualquer NpcController, incluindo objectos
// genéricos reutilizados como interactivos (Ponto 9 da especificação): um
// objecto pode verificar se o jogador tem uma pista ou ouviu um rumor e, em
// caso afirmativo, executar ações configuradas no Inspector (revelar portal,
// activar objecto, alterar variável, avançar tarefa, etc.) através de
// Action_ConditionalBranch.

/// <summary>O jogador já obteve a pista "clueId" da missão indicada (Action_ShowFullscreenImage com "saveAsClue").</summary>
[System.Serializable]
public class Condition_HasClue : NpcCondition
{
    public MissionData mission;

    [Tooltip("Identificador da pista dentro de \"mission.clues\".")]
    public string clueId;

    public override bool Evaluate(NpcController npc)
    {
        return JournalManager.Instance != null && mission != null && JournalManager.Instance.HasClue(mission, clueId);
    }
}

/// <summary>O jogador já ouviu este rumor (Action_AddRumor) — aparece na secção "Rumores" do Diário.</summary>
[System.Serializable]
public class Condition_HeardRumor : NpcCondition
{
    public RumorData rumor;

    public override bool Evaluate(NpcController npc)
    {
        return JournalManager.Instance != null && JournalManager.Instance.HasHeardRumor(rumor);
    }
}

/// <summary>Este rumor já foi marcado como "encontrado" (Action_MarkRumorFound — ícone de "Check" no Diário).</summary>
[System.Serializable]
public class Condition_RumorFound : NpcCondition
{
    public RumorData rumor;

    public override bool Evaluate(NpcController npc)
    {
        return JournalManager.Instance != null && JournalManager.Instance.IsRumorFound(rumor);
    }
}
